let netWorth = 0;
let totalInvestment = 0;
let unrealizedPL = 0;
let reitValue = 0;

let portfolio = [];

for (const item of $input.all()) {

  const price = Number(item.json["CMP"]);
  const qty = Number(item.json["Holding Units"]);
  const avgPrice = Number(item.json["Buy Price"]);
  const industry = item.json["Industry"];

  const currentValue = Math.round(price * qty);
  const investment = Math.round(avgPrice * qty);
  const pl = Math.round(currentValue - investment);

  if (industry === "REITS") {
    reitValue += currentValue;
  } else {
    netWorth += currentValue;
    totalInvestment += investment;
    unrealizedPL += pl;
  }

  // Only include active holdings
  if (qty > 0) {
    portfolio.push({
      name: item.json["Name"],
      sector: item.json["Sector"],
      industry: item.json["Industry"],
      qty,
      daysChange:item.json["Day's Change"]
      ,
      currentValue,
      investment,
      pl,
      plPercent: item.json["Profit/Loss Percentage"]
    });
  }
}

return [{
  json: {
    netWorth: Math.round(netWorth),
    totalInvestment: Math.round(totalInvestment),
    unrealizedPL: Math.round(unrealizedPL),
    reitValue: Math.round(reitValue),
    portfolio
  }
}];

let fiiFlow = 0;
let diiFlow = 0;
let datee = "";

for (const item of $input.all()) {

  if (!datee) {
    datee = item.json.date; // capture date once
  }

  if (item.json.category === "FII/FPI") {
    fiiFlow = Math.round(Number(item.json.netValue));
  }

  if (item.json.category === "DII") {
    diiFlow = Math.round(Number(item.json.netValue));
  }
}

return [{
  json: {
    datee,
    fiiFlow,
    diiFlow,
    netFIIDII: fiiFlow + diiFlow
  }
}];

